/* DMA controller abstraction layer */
#ifndef DMA_HAL_H
#define DMA_HAL_H

#include <stdint.h>

typedef void (*dma_complete_cb_t)(uint8_t channel, int status);

#define DMA_DIR_MEM_TO_PERIPH  0
#define DMA_DIR_PERIPH_TO_MEM  1
#define DMA_DIR_MEM_TO_MEM     2

typedef struct {
    uint32_t          src_addr;
    uint32_t          dst_addr;
    uint16_t          length;
    uint8_t           direction;   /* DMA_DIR_* */
    uint8_t           priority;    /* 0=low .. 3=high */
    dma_complete_cb_t callback;
} dma_transfer_t;

int  dma_start(uint8_t channel, const dma_transfer_t *xfer);
int  dma_abort(uint8_t channel);
uint16_t dma_remaining(uint8_t channel);

#endif

