/* DMA controller abstraction layer */
#ifndef DMA_HAL_H
#define DMA_HAL_H

#include <stdint.h>

/* Callback signature changed: channel removed, user_data added */
typedef void (*dma_complete_cb_t)(int status, void *user_data);

#define DMA_DIR_MEM_TO_PERIPH  0
#define DMA_DIR_PERIPH_TO_MEM  1
#define DMA_DIR_MEM_TO_MEM     2

typedef struct {
    uint32_t          src_addr;
    uint32_t          dst_addr;
    uint32_t          length;      /* CHANGED: uint16_t -> uint32_t (field size change) */
    uint8_t           direction;   /* DMA_DIR_* */
    uint8_t           priority;    /* 0=low .. 3=high */
    dma_complete_cb_t callback;
    void             *user_data;   /* NEW: passed to callback */
} dma_transfer_t;

int  dma_start(uint8_t channel, const dma_transfer_t *xfer);
int  dma_abort(uint8_t channel);
/* dma_remaining return type changed to uint32_t to match new length field */
uint32_t dma_remaining(uint8_t channel);

#endif

